  const rb=document.getElementById('dbhbtn_real'), ib=document.getElementById('dbhbtn_idbh');
  if(rb&&ib){ rb.classList.toggle('active',m!=='idbh'); ib.classList.toggle('active',m==='idbh'); }
  refreshStandInfoDirty(s.stand_id);
