    plotsForStand(id).forEach(p=>{
      Object.keys(state.trees).forEach(tk=>{ if(state.trees[tk].plot_key===p.plot_key) delete state.trees[tk]; });
      delete state.plots[p.plot_key];
    });
    delete state.stands[id];
    if(state.standInfoStatus) delete state.standInfoStatus[id];
