// ============================================================
//  EXPORT
// ============================================================
function blankRow(headers){ const o={}; headers.forEach(h=>o[h]=""); return o; }
function standBaseFields(s){
  const southern=s.variant==='SN';
  return {
    VARIANT:s.variant, INV_YEAR:s.inv_year, LATITUDE:s.latitude, LONGITUDE:s.longitude,
    LOCATION:s.location, ECOREGION:southern?(s.ecoregion||''):'',
    PV_CODE:southern?'':(s.pv_code||''), PV_REF_CODE:southern?'':(s.pv_ref_code||''), ELEVFT:s.elevation,
    ASPECT:s.aspect, SLOPE:s.slope
  };
}
const DEAD_HISTORY_CODE="6", LIVE_HISTORY_CODE="1";
function gatherExportData(standIds, standOverrides){
  const standRows=[], plotRows=[], treeRows=[], metaRows=[];
  standIds.forEach(sid=>{
    const s=(standOverrides&&standOverrides[sid])||state.stands[sid]; if(!s) return;
    const plots=plotsForStand(sid);
    const sr=blankRow(STAND_HEADERS); Object.assign(sr, standBaseFields(s));
    sr.STAND_ID=s.stand_id; sr.NUM_PLOTS=plots.length;
    sr.BASAL_AREA_FACTOR=s.baf||"";
    sr.INV_PLOT_SIZE=(s.denom!==undefined&&s.denom!=="")?s.denom:"";
    sr.BRK_DBH=(s.brk_dbh!==undefined&&s.brk_dbh!=="")?s.brk_dbh:"";
    standRows.push(sr);
    plots.forEach(p=>{
      const pr=blankRow(PLOT_HEADERS); Object.assign(pr, standBaseFields(s));
      pr.STAND_ID=s.stand_id; pr.PLOT_ID=p.plot_id; pr.STANDPLOT_ID=standplotId(s.stand_id,p.plot_id);
      pr.LATITUDE=p.lat||s.latitude; pr.LONGITUDE=p.lon||s.longitude;
      pr.ASPECT=p.aspect||s.aspect; pr.SLOPE=p.slope||s.slope; pr.NUM_PLOTS=1;
      pr.BASAL_AREA_FACTOR=s.baf||"";
      pr.INV_PLOT_SIZE=(s.denom!==undefined&&s.denom!=="")?s.denom:"";
      pr.BRK_DBH=(s.brk_dbh!==undefined&&s.brk_dbh!=="")?s.brk_dbh:"";
      plotRows.push(pr);
      treesForPlot(p.plot_key).forEach(t=>{
        const tr=blankRow(TREE_HEADERS);
        tr.STAND_ID=s.stand_id; tr.PLOT_ID=p.plot_id; tr.STANDPLOT_ID=standplotId(s.stand_id,p.plot_id);
        tr.TREE_ID=t.tree_id; tr.TREE_COUNT=t.count||"1";
        tr.HISTORY=t.status==="dead"?DEAD_HISTORY_CODE:LIVE_HISTORY_CODE;
        tr.SPECIES=t.species; tr.DIAMETER=t.dbh; tr.HT=t.ht; tr.CRRATIO=t.crown_ratio;
        tr.AGE=t.age||"";
        tr.DAMAGE1=t.damage1; tr.SEVERITY1=t.severity1; tr.DAMAGE2=t.damage2; tr.SEVERITY2=t.severity2;
        tr.DAMAGE3=t.damage3; tr.SEVERITY3=t.severity3;
        tr.SLOPE=p.slope; tr.ASPECT=p.aspect;
        treeRows.push(tr);
      });
    });
    metaRows.push({STAND_ID:s.stand_id, CREW:s.crew, DATE:s.date, NOTES:s.notes});
  });
  return {standRows, plotRows, treeRows, metaRows};
}
function toCSV(rows, headers){
  const esc=v=>{ v=(v==null)?"":String(v); return /[",\r\n]/.test(v)?'"'+v.replace(/"/g,'""')+'"':v; };
  const cols=headers||(rows.length?Object.keys(rows[0]):[]);
  const lines=[cols.join(",")];
  rows.forEach(r=>lines.push(cols.map(c=>esc(r[c])).join(",")));
  return lines.join("\n");
}
function makeExportFile(parts, name, type){
  try{ return new File(parts,name,{type,lastModified:Date.now()}); }
  catch(error){ const blob=new Blob(parts,{type}); blob.name=name; return blob; }
}
function downloadFile(file, name){
  const filename=name||file.name||"plotter-export";
  const url=URL.createObjectURL(file);
  const a=document.createElement('a');
  a.href=url; a.download=filename; a.rel='noopener';
  document.body.appendChild(a); a.click(); a.remove();
  window.setTimeout(()=>URL.revokeObjectURL(url),30000);
}
async function deliverFiles(files, bundleName){
  if(!files.length) throw new Error("No files were created.");
  if(navigator.share && navigator.canShare){
    try{
      const payload={title:"plOtter FVS export",files};
      if(navigator.canShare(payload)){
        await navigator.share(payload);
        return "shared";
      }
    }catch(error){
      if(error && error.name==='AbortError') return "cancelled";
      console.warn("Share sheet unavailable; using browser download.",error);
    }
  }
  if(files.length===1){
    downloadFile(files[0]);
    return "downloaded";
  }
  const zip=new JSZip();
  for(const file of files){
    zip.file(file.name,new Uint8Array(await file.arrayBuffer()));
  }
  const bytes=await zip.generateAsync({type:"uint8array",compression:"DEFLATE",compressionOptions:{level:6}});
  const archive=makeExportFile([bytes],bundleName,"application/zip");
  downloadFile(archive);
  return "zipped";
}
function getSelectedStandIds(){ return Array.from(document.querySelectorAll('.exp-check:checked')).map(el=>el.value); }
function focusStandInfo(standId){
  state.activeStand=standId||state.activeStand;
  state.activePlot=null;
  ui.tab='stand';
  render();
  window.setTimeout(()=>document.getElementById('standInfoCard')?.scrollIntoView({block:'start'}),0);
}
function exportStandWarningDialog(mode, standIds){
  return new Promise(resolve=>{
    const overlay=document.createElement('div');
    overlay.className='modal-overlay';
    const names=standIds.map(escapeHTML).join(', ');
    const never=mode==='never';
    overlay.innerHTML=`<div class="choice-dialog" role="dialog" aria-modal="true" aria-labelledby="export-warning-title">
      <h2 id="export-warning-title">${never?'Save Stand Info before exporting':'Unsaved Stand Info'}</h2>
      <p>${never
        ?`The following selected stand${standIds.length===1?' has':'s have'} never been saved: <strong>${names}</strong>. Export is blocked until Stand Info is saved.`
        :`The following selected stand${standIds.length===1?' has':'s have'} unsaved Stand Info: <strong>${names}</strong>. Choose whether to return and save, or export the last saved values.`}</p>
      <div class="choice-dialog-actions">
        <button type="button" class="secondary" data-action="return">Return to Stand Info</button>
        ${never?'<button type="button" data-action="cancel">Cancel</button>':'<button type="button" data-action="last-saved">Export Last Saved Values</button>'}
      </div>
    </div>`;
    document.body.appendChild(overlay);
    const close=value=>{ overlay.remove(); resolve(value); };
    overlay.querySelector('[data-action="return"]').onclick=()=>close('return');
    const other=overlay.querySelector(never?'[data-action="cancel"]':'[data-action="last-saved"]');
    other.onclick=()=>close(never?'cancel':'last-saved');
    window.setTimeout(()=>overlay.querySelector('[data-action="return"]')?.focus(),0);
  });
}
async function prepareExportStandSources(standIds){
  const neverSaved=standIds.filter(id=>!hasSavedStandInfo(id));
  if(neverSaved.length){
    const action=await exportStandWarningDialog('never',neverSaved);
    if(action==='return') focusStandInfo(neverSaved[0]);
    return null;
  }
  const dirty=standIds.filter(id=>getStandInfoStatus(id).dirty);
  if(!dirty.length) return {standOverrides:{},usedLastSaved:false};
  const action=await exportStandWarningDialog('dirty',dirty);
  if(action!=='last-saved'){
    focusStandInfo(dirty[0]);
    return null;
  }
  const standOverrides={};
  dirty.forEach(id=>{ standOverrides[id]=JSON.parse(JSON.stringify(getStandInfoStatus(id).snapshot)); });
  return {standOverrides,usedLastSaved:true};
}
function exportStamp(){
  const d=new Date(), p=n=>String(n).padStart(2,'0');
  return d.getFullYear()+'-'+p(d.getMonth()+1)+'-'+p(d.getDate())+'_'+p(d.getHours())+p(d.getMinutes())+p(d.getSeconds());
}
async function exportCSV(){
  const ids=getSelectedStandIds(); if(!ids.length){ toast("Select at least one stand"); return; }
  try{
    const exportPlan=await prepareExportStandSources(ids); if(!exportPlan) return;
    const {standRows, plotRows, treeRows}=gatherExportData(ids,exportPlan.standOverrides);
    const ts=exportStamp();
    const files=[
      makeExportFile([toCSV(standRows,STAND_HEADERS)],"FVS_StandInit_"+ts+".csv","text/csv;charset=utf-8"),
      makeExportFile([toCSV(plotRows,PLOT_HEADERS)],"FVS_PlotInit_"+ts+".csv","text/csv;charset=utf-8"),
      makeExportFile([toCSV(treeRows,TREE_HEADERS)],"FVS_TreeInit_"+ts+".csv","text/csv;charset=utf-8")
    ];
    const result=await deliverFiles(files,"FVS_CSV_Export_"+ts+".zip");
    if(result==="shared") toast("3 CSV files shared");
    else if(result==="zipped") toast("3 CSV files saved in one ZIP archive");
    else if(result==="cancelled") toast("Export cancelled");
    else toast("CSV files downloaded");
  }catch(error){
    console.error("CSV export failed",error);
    toast("⚠ CSV export failed");
  }
}
async function exportXLSX(){
  const ids=getSelectedStandIds(); if(!ids.length){ toast("Select at least one stand"); return; }
  try{
    if(!window.FVSXLSX) throw new Error("Offline Excel module did not load.");
    const exportPlan=await prepareExportStandSources(ids); if(!exportPlan) return;
    toast("Preparing Excel workbook…");
    const {standRows, plotRows, treeRows, metaRows}=gatherExportData(ids,exportPlan.standOverrides);
    const out=await window.FVSXLSX.writeWorkbook([
      {name:"FVS_StandInit",headers:STAND_HEADERS,rows:standRows},
      {name:"FVS_PlotInit",headers:PLOT_HEADERS,rows:plotRows},
      {name:"FVS_TreeInit",headers:TREE_HEADERS,rows:treeRows},
      {name:"FieldMetadata",headers:["STAND_ID","CREW","DATE","NOTES"],rows:metaRows}
    ]);
    const filename="FVS_Export_"+exportStamp()+".xlsx";
    const file=makeExportFile([out],filename,"application/vnd.openxmlformats-officedocument.spreadsheetml.sheet");
    const result=await deliverFiles([file],filename);
    if(result==="shared") toast("Excel workbook shared");
    else if(result==="cancelled") toast("Export cancelled");
    else toast("Excel workbook downloaded");
  }catch(error){
    console.error("Excel export failed",error);
    toast("⚠ Excel export failed");
  }
}
// ---- Import: merge a plOtter Excel/CSV export from another device ----
function triggerImport(){ const el=document.getElementById('importFile'); if(el) el.click(); }
function sheetRows(wb,name){ const rows=wb && wb.Sheets && wb.Sheets[name]; return Array.isArray(rows)?rows:[]; }
async function importCSVArchive(file){
  const zip=await JSZip.loadAsync(await file.arrayBuffer());
  const entries=Object.values(zip.files)
    .filter(entry=>!entry.dir && /\.csv$/i.test(entry.name))
    .map(entry=>({name:entry.name.split('/').pop(),text:()=>entry.async('string')}));
  if(!entries.length) throw new Error("The ZIP archive contains no CSV files.");
  await importCSVFiles(entries);
}
async function handleImportFile(evt){
  const files=Array.from(evt.target.files||[]); if(!files.length) return;
  try{
    const xlsx=files.filter(f=>/\.xlsx$/i.test(f.name));
    const csv=files.filter(f=>/\.csv$/i.test(f.name));
    const archives=files.filter(f=>/\.zip$/i.test(f.name));
    if(xlsx.length){
      for(const file of xlsx){
        const wb=await window.FVSXLSX.readWorkbook(await file.arrayBuffer());
        importWorkbook(wb);
      }
    }
    if(csv.length) await importCSVFiles(csv);
    for(const archive of archives) await importCSVArchive(archive);
    if(!xlsx.length && !csv.length && !archives.length) toast("Select a .xlsx, FVS .csv, or CSV .zip file");
  }catch(error){
    console.error("import failed",error);
    toast("⚠ Import failed — check the selected file(s)");
  }
  evt.target.value='';
}
function parseCSVtext(text){
  const rows=[]; let row=[], field='', i=0, inQ=false;
  text=text.replace(/\r\n/g,'\n').replace(/\r/g,'\n');
  while(i<text.length){
    const c=text[i];
    if(inQ){
      if(c==='"'){ if(text[i+1]==='"'){ field+='"'; i+=2; continue; } inQ=false; i++; continue; }
      field+=c; i++; continue;
    } else {
      if(c==='"'){ inQ=true; i++; continue; }
      if(c===','){ row.push(field); field=''; i++; continue; }
      if(c==='\n'){ row.push(field); rows.push(row); row=[]; field=''; i++; continue; }
      field+=c; i++; continue;
    }
  }
  if(field!==''||row.length){ row.push(field); rows.push(row); }
  return rows;
}
function csvToObjects(text){
  const rows=parseCSVtext(text).filter(r=>r.length && !(r.length===1 && String(r[0]).trim()===''));
  if(!rows.length) return [];
  const headers=rows[0].map(h=>String(h).replace(/^\uFEFF/,'').trim());
  return rows.slice(1).map(r=>{ const o={}; headers.forEach((h,idx)=>{ o[h]=r[idx]!==undefined?r[idx]:''; }); return o; });
}
async function importCSVFiles(files){
  let standRows=[], plotRows=[], treeRows=[];
  for(const f of files){
    const objs=csvToObjects(await f.text());
    const nm=f.name.toLowerCase();
    let kind='';
    if(nm.includes('standinit')) kind='stand';
    else if(nm.includes('plotinit')) kind='plot';
    else if(nm.includes('treeinit')) kind='tree';
    else { const h=objs.length?Object.keys(objs[0]):[];
      if(h.includes('TREE_ID')||h.includes('DIAMETER')) kind='tree';
      else if(h.includes('PLOT_ID')||h.includes('STANDPLOT_ID')) kind='plot';
      else if(h.includes('STAND_ID')) kind='stand'; }
    if(kind==='stand') standRows=standRows.concat(objs);
    else if(kind==='plot') plotRows=plotRows.concat(objs);
    else if(kind==='tree') treeRows=treeRows.concat(objs);
  }
  importData({standRows, plotRows, treeRows, metaRows:[]});
}
function mkStandFromRow(id,r,m){
  const variant=String(r.VARIANT||'').trim();
  return { stand_id:id, variant, inv_year:r.INV_YEAR||'',
    region:'',forest:'',district:'',location:String(r.LOCATION||'').trim(),
    crew:(m&&m.CREW)||'', date:(m&&m.DATE)||'', site_species:'',site_index:'',
    ecoregion:String(r.ECOREGION||'').trim(),
    pv_code:variant==='SN'?'':String(r.PV_CODE||'').trim(), pv_ref_code:variant==='SN'?'':String(r.PV_REF_CODE||'').trim(),
    elevation:r.ELEVFT||'', latitude:r.LATITUDE||'', longitude:r.LONGITUDE||'',
    slope:r.SLOPE||'', aspect:r.ASPECT||'', state_cd:'',county:'', notes:(m&&m.NOTES)||'',
    baf:r.BASAL_AREA_FACTOR||'', denom:(r.INV_PLOT_SIZE!==undefined?String(r.INV_PLOT_SIZE):''), brk_dbh:(r.BRK_DBH!==undefined?String(r.BRK_DBH):'') };
}
function importWorkbook(wb){
  importData({
    standRows:sheetRows(wb,'FVS_StandInit'),
    plotRows:sheetRows(wb,'FVS_PlotInit'),
    treeRows:sheetRows(wb,'FVS_TreeInit'),
    metaRows:sheetRows(wb,'FieldMetadata')
  });
}
function importData(bundle){
  const standRows=bundle.standRows||[], plotRows=bundle.plotRows||[], treeRows=bundle.treeRows||[], metaRows=bundle.metaRows||[];
  if(!standRows.length && !plotRows.length && !treeRows.length){ toast("No FVS data found to import"); return; }
  const meta={}; metaRows.forEach(r=>{ const id=String(r.STAND_ID||'').trim(); if(id) meta[id]=r; });
  let addedStands=0, addedPlots=0, addedTrees=0, skippedPlots=0;
  const importedStandIds=new Set();
  const touchedStandIds=new Set();
  standRows.forEach(r=>{ const id=String(r.STAND_ID||'').trim(); if(!id) return;
    touchedStandIds.add(id);
    if(!state.stands[id]){ state.stands[id]=mkStandFromRow(id,r,meta[id]); importedStandIds.add(id); addedStands++; } });
  const keyByPair={}; Object.values(state.plots).forEach(p=>{ keyByPair[p.stand_id+'|'+p.plot_id]=p.plot_key; });
  const newPlotKeys={};
  plotRows.forEach(r=>{ const sid=String(r.STAND_ID||'').trim(); const pid=parseInt(r.PLOT_ID);
    if(!sid||isNaN(pid)) return;
    touchedStandIds.add(sid);
    if(!state.stands[sid]){ state.stands[sid]=mkStandFromRow(sid,r,meta[sid]); importedStandIds.add(sid); addedStands++; }
    else {
      const stand=state.stands[sid];
      if(!stand.variant && r.VARIANT) stand.variant=String(r.VARIANT).trim();
      if(!stand.ecoregion && r.ECOREGION!==undefined && r.ECOREGION!==null) stand.ecoregion=String(r.ECOREGION).trim();
      if(stand.variant==='SN'){ stand.pv_code=''; stand.pv_ref_code=''; }
    }
    const pair=sid+'|'+pid;
    if(keyByPair[pair]!==undefined){ skippedPlots++; return; }
    const key=uid("plot");
    state.plots[key]={ plot_key:key, stand_id:sid, plot_id:pid, lat:r.LATITUDE||'', lon:r.LONGITUDE||'', slope:r.SLOPE||'', aspect:r.ASPECT||'', treeCounter:0 };
    keyByPair[pair]=key; newPlotKeys[key]=true; addedPlots++;
  });
  treeRows.forEach(r=>{ const sid=String(r.STAND_ID||'').trim(); const pid=parseInt(r.PLOT_ID);
    if(!sid||isNaN(pid)) return;
    const pk=keyByPair[sid+'|'+pid];
    if(pk===undefined || !newPlotKeys[pk]) return;
    const plot=state.plots[pk];
    let tid=parseInt(r.TREE_ID); if(isNaN(tid)) tid=(plot.treeCounter||0)+1;
    plot.treeCounter=Math.max(plot.treeCounter||0, tid);
    const hist=String(r.HISTORY||'').trim();
    const tkey=uid("tree");
    state.trees[tkey]={ tree_key:tkey, plot_key:pk, stand_id:sid, tree_id:tid,
      count:(r.TREE_COUNT!==undefined&&r.TREE_COUNT!==''?String(r.TREE_COUNT):'1'),
      species:String(r.SPECIES||'').trim(), status:(hist==='6'?'dead':'live'),
      dbh:(r.DIAMETER!==undefined?String(r.DIAMETER):''), ht:(r.HT!==undefined?String(r.HT):''),
      crown_ratio:(r.CRRATIO!==undefined?String(r.CRRATIO):''), age:(r.AGE!==undefined?String(r.AGE):''),
      damage1:String(r.DAMAGE1||''), severity1:String(r.SEVERITY1||''),
      damage2:String(r.DAMAGE2||''), severity2:String(r.SEVERITY2||'') };
    addedTrees++;
  });
  importedStandIds.forEach(markStandInfoSaved);
  touchedStandIds.forEach(id=>{ if(!importedStandIds.has(id)) refreshStandInfoDirty(id); });
  saveState(); ui.tab='review'; render();
  toast("Imported "+addedStands+" stands, "+addedPlots+" plots, "+addedTrees+" trees"+(skippedPlots?" · "+skippedPlots+" existing plots skipped":""));
}

// ============================================================
//  RENDER
// ============================================================
// ============================================================
//  LOCATION CODES per variant  [code, description]
//  Value exported to FVS = numeric code; description shown in dropdown.
//  Ordering is applied at render (sortLocationCodes): tribal-land
//  codes first (numeric), then all others (numeric).
// ============================================================
const TRIBAL_KEYWORDS = /reservation|rancheria|colony|pueblo|community|otsa|tdsa|anvsa|trust land|tribe|tribal|\bband\b|\bnation\b|sioux|chippewa|potawatomi|pequot|maliseet|micmac|wampanoag/i;
function locNum(code){ const m=String(code).match(/\d+/); return m?parseInt(m[0],10):999999; }
function sortLocationCodes(codes, variant){
  if(variant==="AK"){
    // AK: codes 7400–8135 first (numeric), then the rest (numeric)
    return codes.slice().sort((a,b)=>{
      const na=locNum(a[0]), nb=locNum(b[0]);
      const pa=(na>=7400&&na<=8135), pb=(nb>=7400&&nb<=8135);
      if(pa!==pb) return pa?-1:1;
      return na-nb;
    });
  }
  return codes.slice().sort((a,b)=>{
    const ta=TRIBAL_KEYWORDS.test(a[1]||""), tb=TRIBAL_KEYWORDS.test(b[1]||"");
    if(ta!==tb) return ta?-1:1;
    return locNum(a[0])-locNum(b[0]);
  });
}
