function variantOptions(selected){
  let opts = VARIANTS.map(([c,n])=>`<option value="${c}" ${c===selected?'selected':''}>${c} — ${n}</option>`).join("");
  if(selected && !VARIANTS.some(v=>v[0]===selected)){
    opts = `<option value="${selected}" selected>${selected} (custom)</option>`+opts;
  }
  return `<option value="" ${selected?'':'selected'}>— select —</option>`+opts;
}
function locationOptions(variant, selected){
  const codes = sortLocationCodes(LOCATION_CODES[variant] || [], variant);
  let opts = `<option value="">— none / N/A —</option>`;
  opts += codes.map(([c,n])=>`<option value="${c}" ${c===selected?'selected':''}>${c} — ${n}</option>`).join("");
  if(selected && !codes.some(x=>x[0]===selected)){
    opts += `<option value="${selected}" selected>${selected} (custom)</option>`;
  }
  return opts;
}
function updateLocationOptions(selected){
  const vSel=document.getElementById('f_variant');
  const lSel=document.getElementById('f_location');
  if(!vSel||!lSel) return;
  const keep=selected!==undefined?selected:lSel.value;
  lSel.innerHTML=locationOptions(vSel.value,keep);
}

