    let opts=`<option value="">—</option>`;
    for(let i=1;i<=6;i++) opts+=`<option value="${i}" ${String(sevVal)===String(i)?'selected':''}>${i}</option>`;
    return `<select id="t_sev${idx}" style="width:100%">${opts}</select>`;
